import{_ as a,o,c as t,a3 as i}from"./chunks/framework.DACwFHq9.js";const m=JSON.parse('{"title":"Top Common Tasks","description":"","frontmatter":{},"headers":[],"relativePath":"top-tasks.md","filePath":"top-tasks.md","lastUpdated":1784057516000}'),r={name:"top-tasks.md"};function l(n,e,s,d,c,h){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="top-common-tasks" tabindex="-1">Top Common Tasks <a class="header-anchor" href="#top-common-tasks" aria-label="Permalink to &quot;Top Common Tasks&quot;">​</a></h1><p>Use this page when you want quick, direct steps.</p><h2 id="_1-open-or-change-workspace" tabindex="-1">1. Open or change workspace <a class="header-anchor" href="#_1-open-or-change-workspace" aria-label="Permalink to &quot;1. Open or change workspace&quot;">​</a></h2><ol><li>Open <strong>File -&gt; Open Workspace</strong>.</li><li>Select the folder.</li><li>Confirm.</li></ol><h2 id="_2-create-a-new-note" tabindex="-1">2. Create a new note <a class="header-anchor" href="#_2-create-a-new-note" aria-label="Permalink to &quot;2. Create a new note&quot;">​</a></h2><ol><li>Open <strong>File -&gt; New Note</strong> (<code>Ctrl/Cmd + N</code>).</li><li>Enter note name.</li><li>Start writing.</li></ol><h2 id="_3-create-a-folder" tabindex="-1">3. Create a folder <a class="header-anchor" href="#_3-create-a-folder" aria-label="Permalink to &quot;3. Create a folder&quot;">​</a></h2><ol><li>Use folder controls in the list view.</li><li>Enter folder name.</li><li>Save.</li></ol><h2 id="_4-find-text-in-current-note" tabindex="-1">4. Find text in current note <a class="header-anchor" href="#_4-find-text-in-current-note" aria-label="Permalink to &quot;4. Find text in current note&quot;">​</a></h2><ol><li>Press <code>Ctrl/Cmd + F</code>.</li><li>Enter text.</li><li>Use next/previous controls.</li></ol><h2 id="_5-replace-text-in-current-note" tabindex="-1">5. Replace text in current note <a class="header-anchor" href="#_5-replace-text-in-current-note" aria-label="Permalink to &quot;5. Replace text in current note&quot;">​</a></h2><ol><li>Open find panel.</li><li>Enter find and replace text.</li><li>Run replace or replace all.</li></ol><h2 id="_6-switch-between-edit-split-and-preview" tabindex="-1">6. Switch between Edit, Split, and Preview <a class="header-anchor" href="#_6-switch-between-edit-split-and-preview" aria-label="Permalink to &quot;6. Switch between Edit, Split, and Preview&quot;">​</a></h2><ol><li>Open view mode controls in the editor header.</li><li>Choose the mode that fits your task.</li></ol><h2 id="_7-show-document-outline" tabindex="-1">7. Show document outline <a class="header-anchor" href="#_7-show-document-outline" aria-label="Permalink to &quot;7. Show document outline&quot;">​</a></h2><ol><li>Open <strong>View -&gt; Show Outline</strong>.</li><li>Click section headings to jump.</li></ol><h2 id="_8-enable-focus-mode" tabindex="-1">8. Enable Focus Mode <a class="header-anchor" href="#_8-enable-focus-mode" aria-label="Permalink to &quot;8. Enable Focus Mode&quot;">​</a></h2><ol><li>Open <strong>View -&gt; Focus Mode</strong>.</li><li>Toggle off when done.</li></ol><h2 id="_9-insert-an-image-into-a-note" tabindex="-1">9. Insert an image into a note <a class="header-anchor" href="#_9-insert-an-image-into-a-note" aria-label="Permalink to &quot;9. Insert an image into a note&quot;">​</a></h2><ol><li>Use markdown toolbar image action.</li><li>Pick file.</li><li>Confirm insertion.</li></ol><h2 id="_10-insert-a-mermaid-diagram" tabindex="-1">10. Insert a Mermaid diagram <a class="header-anchor" href="#_10-insert-a-mermaid-diagram" aria-label="Permalink to &quot;10. Insert a Mermaid diagram&quot;">​</a></h2><ol><li>Use toolbar diagram action.</li><li>Select Mermaid.</li><li>Add Mermaid syntax.</li><li>Check rendering in preview.</li></ol><h2 id="_11-insert-an-excalidraw-diagram" tabindex="-1">11. Insert an Excalidraw diagram <a class="header-anchor" href="#_11-insert-an-excalidraw-diagram" aria-label="Permalink to &quot;11. Insert an Excalidraw diagram&quot;">​</a></h2><ol><li>Use toolbar diagram action.</li><li>Select Excalidraw.</li><li>Edit and save.</li></ol><h2 id="_11b-convert-an-image-to-excalidraw" tabindex="-1">11b. Convert an image to Excalidraw <a class="header-anchor" href="#_11b-convert-an-image-to-excalidraw" aria-label="Permalink to &quot;11b. Convert an image to Excalidraw&quot;">​</a></h2><ol><li>In preview, right-click a workspace image.</li><li>Choose <strong>Edit with Excalidraw</strong>.</li><li>Draw and resize the base image as needed.</li><li>Save diagram.</li></ol><h2 id="_12-view-or-restore-note-history" tabindex="-1">12. View or restore note history <a class="header-anchor" href="#_12-view-or-restore-note-history" aria-label="Permalink to &quot;12. View or restore note history&quot;">​</a></h2><ol><li>Click the <strong>History</strong> button in the note&#39;s top-right toolbar or press <code>Ctrl/Cmd + Shift + H</code>.</li><li>Select a commit from the history timeline sidebar.</li><li>Compare revisions or click <strong>Restore</strong> to revert changes.</li></ol><h2 id="_13-search-across-all-notes" tabindex="-1">13. Search across all notes <a class="header-anchor" href="#_13-search-across-all-notes" aria-label="Permalink to &quot;13. Search across all notes&quot;">​</a></h2><ol><li>Open global search.</li><li>Enter keyword.</li><li>Open matching result.</li></ol><h2 id="_14-open-keyboard-shortcuts" tabindex="-1">14. Open keyboard shortcuts <a class="header-anchor" href="#_14-open-keyboard-shortcuts" aria-label="Permalink to &quot;14. Open keyboard shortcuts&quot;">​</a></h2><ol><li>Open <strong>Help -&gt; Keyboard Shortcuts</strong>.</li><li>Use it as a quick command reference.</li></ol><h2 id="_15-open-troubleshooting" tabindex="-1">15. Open troubleshooting <a class="header-anchor" href="#_15-open-troubleshooting" aria-label="Permalink to &quot;15. Open troubleshooting&quot;">​</a></h2><ol><li>Open <strong>Help -&gt; Help Center</strong> (<code>F1</code>).</li><li>Select <strong>Troubleshooting</strong> in the left menu.</li></ol><h2 id="_16-run-ai-setup-and-test" tabindex="-1">16. Run AI setup and test <a class="header-anchor" href="#_16-run-ai-setup-and-test" aria-label="Permalink to &quot;16. Run AI setup and test&quot;">​</a></h2><ol><li>Open <strong>AI -&gt; AI Settings</strong>.</li><li>Add your sign-in details for the AI service you want to use.</li><li>Run the connection test.</li></ol><h2 id="_17-refresh-semantic-graph-data" tabindex="-1">17. Refresh semantic graph data <a class="header-anchor" href="#_17-refresh-semantic-graph-data" aria-label="Permalink to &quot;17. Refresh semantic graph data&quot;">​</a></h2><ol><li>Open <strong>Workspace -&gt; Workspace Graph</strong>.</li><li>Use graph refresh action.</li><li>Verify freshness indicator updates.</li></ol><h2 id="_18-clean-unused-media" tabindex="-1">18. Clean unused media <a class="header-anchor" href="#_18-clean-unused-media" aria-label="Permalink to &quot;18. Clean unused media&quot;">​</a></h2><ol><li>Open media management/health view.</li><li>Filter by unused media.</li><li>Run bulk delete for confirmed unused files.</li></ol><h2 id="_19-restore-original-image-after-edits" tabindex="-1">19. Restore original image after edits <a class="header-anchor" href="#_19-restore-original-image-after-edits" aria-label="Permalink to &quot;19. Restore original image after edits&quot;">​</a></h2><ol><li>Open image editor for a previously edited image.</li><li>Choose restore original.</li><li>Confirm restore action.</li></ol><h2 id="_19b-restore-original-image-from-converted-excalidraw" tabindex="-1">19b. Restore original image from converted Excalidraw <a class="header-anchor" href="#_19b-restore-original-image-from-converted-excalidraw" aria-label="Permalink to &quot;19b. Restore original image from converted Excalidraw&quot;">​</a></h2><ol><li>Right-click an Excalidraw preview that came from image conversion.</li><li>Choose <strong>Restore original image</strong>.</li></ol><h2 id="_20-export-a-note-to-pdf" tabindex="-1">20. Export a note to PDF <a class="header-anchor" href="#_20-export-a-note-to-pdf" aria-label="Permalink to &quot;20. Export a note to PDF&quot;">​</a></h2><ol><li>Open note actions for export.</li><li>Choose PDF export.</li><li>Select destination and confirm.</li></ol><h2 id="_21-capture-a-screen-area-into-a-note" tabindex="-1">21. Capture a screen area into a note <a class="header-anchor" href="#_21-capture-a-screen-area-into-a-note" aria-label="Permalink to &quot;21. Capture a screen area into a note&quot;">​</a></h2><ol><li>Place cursor in note.</li><li>Click toolbar capture icon or press <code>Ctrl/Cmd + Shift + S</code>.</li><li>Select area in Windows snip overlay.</li><li>If mode is Review, click Save in review dialog.</li></ol><p>Set mode in <strong>Settings -&gt; Screen Capture</strong>.</p><h2 id="_22-review-open-and-completed-tasks-across-workspace" tabindex="-1">22. Review open and completed tasks across workspace <a class="header-anchor" href="#_22-review-open-and-completed-tasks-across-workspace" aria-label="Permalink to &quot;22. Review open and completed tasks across workspace&quot;">​</a></h2><ol><li>Open Command Palette (<code>Ctrl/Cmd + K</code>).</li><li>Run <strong>Open Tasks Panel</strong> to review pending tasks.</li><li>Run <strong>Open All Tasks</strong> to review open + completed tasks together.</li><li>Open source notes directly from task rows.</li></ol><h2 id="_23-export-workspace-as-zip" tabindex="-1">23. Export workspace as zip <a class="header-anchor" href="#_23-export-workspace-as-zip" aria-label="Permalink to &quot;23. Export workspace as zip&quot;">​</a></h2><ol><li>Go to landing view.</li><li>Open <strong>File -&gt; Export Workspace as Zip</strong>.</li><li>Select format (notes as-is, PDF-only, or web format).</li><li>Keep the app data toggle off unless you intentionally need <code>.notes-app</code> data.</li><li>Browse destination and adjust filename if needed.</li><li>Click <strong>Export Zip</strong>.</li></ol>',53)])])}const u=a(r,[["render",l]]);export{m as __pageData,u as default};
